code = """import pandas as pd
import re
import json

# Access the list of business records directly from the previous query_db call.
# Assuming locals()['var_function-call-12672884915346442870'] contains the list of dictionaries.
business_data = locals()['var_function-call-12672884915346442870']['query_db_response']['results'][0]

# The business_data is a string, so we need to parse it as JSON
business_list_of_dicts = json.loads(re.search(r'\[.*\]', business_data, re.DOTALL).group(0))
df_business = pd.DataFrame(business_list_of_dicts)

# Function to extract the state abbreviation from the description
def extract_state(description):
    if isinstance(description, str):
        match = re.search(r',\s*([A-Z]{2})(?:\s|$|,)', description)
        if match:
            return match.group(1)
    return None

df_business['state'] = df_business['description'].apply(extract_state)
df_business_wifi = df_business.dropna(subset=['state'])

# Create 'business_ref' for joining by replacing the prefix
df_business_wifi['business_ref'] = df_business_wifi['business_id'].str.replace('businessid_', 'businessref_')

# Select only relevant columns for the next step: business_ref and state
df_final_business_data = df_business_wifi[['business_ref', 'state']].copy()

# Convert the DataFrame to a JSON string to pass it to the next step
df_final_business_data_json = df_final_business_data.to_json(orient='records')

# Also create the SQL IN clause string for business_refs
business_refs_list = df_final_business_data['business_ref'].tolist()
business_refs_sql_format = ', '.join([f"'{ref}'" for ref in business_refs_list])
business_refs_sql_format = f"({business_refs_sql_format})"

result = {
    'business_refs_sql': business_refs_sql_format,
    'df_final_business_data_json': df_final_business_data_json
}
print("__RESULT__:")
print(json.dumps(result))"""

